export const getCityCodes = () => {
  const codes = {};
  universities.forEach(u => { codes[u.city] = u.cityCode; });
  return codes;
};

export const getUniversitiesByCity = (city) => {
  if (!city) return universities;
  return universities.filter(u => u.city === city);
};

export const getUniversitiesByType = (type) => {
  if (!type) return universities;
  return universities.filter(u => u.type === type);
};

export const uniqueCities = [...new Set(universities.map(u => u.city))].sort();
